MERGE INTO CONSULTAS FIN USING (SELECT '000426ResumenTotalDisponibilidad1' INFORME ,TO_CLOB(q'[SELECT  V_ACUMULADOS.CLASE  CLASE, 
    V_ACUMULADOS.ID_DE_CONCEPTO  ID_DE_CONCEPTO, 
    V_ACUMULADOS.CLASE_NOMBRE_MAYU  CLASECONCEPTO, 
    V_ACUMULADOS.NOMBRE_CONCEPTO  NOMBRE_CONCEPTO, 
    SUM(V_ACUMULADOS.VALOR)  SUMA_DE_VALOR 
FROM V_ACUMULADOS 
WHERE V_ACUMULADOS.COMPANIA =  s$compania$s
AND V_ACUMULADOS.CLASE = 3
AND LPAD(V_ACUMULADOS.ID_DE_PROCESO, 2, 0) || LPAD(V_ACUMULADOS.ANO, 4, 0) || LPAD(V_ACUMULADOS.MES, 2, 0) || LPAD(V_ACUMULADOS.PERIODO, 2, 0) BETWEEN 's$fechaInicial$s'  AND 's$fechaFinal$s'  
GROUP BY V_ACUMULADOS.CLASE,
        V_ACUMULADOS.ID_DE_CONCEPTO,
        V_ACUMULADOS.CLASE_NOMBRE_MAYU,
        V_ACUMULADOS.NOMBRE_CONCEPTO]') CONSULTA, 6 APLICACION ,TO_CLOB(q'[]') CONSULTA_OPCIONAL, NULL CREATED_BY, NULL MODIFIED_BY  FROM DUAL ) INI ON (INI.INFORME = FIN.INFORME )  WHEN MATCHED THEN  UPDATE SET FIN.CONSULTA =  INI.CONSULTA, FIN.APLICACION =  INI.APLICACION, FIN.CONSULTA_OPCIONAL =  INI.CONSULTA_OPCIONAL, FIN.MODIFIED_BY = INI.MODIFIED_BY, FIN.DATE_MODIFIED = SYSDATE  WHEN NOT MATCHED THEN  INSERT (INFORME,CONSULTA, APLICACION,CONSULTA_OPCIONAL,CREATED_BY,DATE_CREATED)  VALUES (INI.INFORME,INI.CONSULTA, INI.APLICACION,INI.CONSULTA_OPCIONAL,INI.CREATED_BY,SYSDATE);